import{_ as t,o as h,c as a,ai as r}from"./chunks/framework.CEPF3YDX.js";const u=JSON.parse('{"title":"Dành cho người khuyết tật","description":"","frontmatter":{},"headers":[],"relativePath":"danh-cho-nguoi-khuyet-tat.md","filePath":"danh-cho-nguoi-khuyet-tat.md"}'),i={name:"danh-cho-nguoi-khuyet-tat.md"};function e(o,n,c,g,d,l){return h(),a("div",null,[...n[0]||(n[0]=[r('<h1 id="danh-cho-nguoi-khuyet-tat" tabindex="-1">Dành cho người khuyết tật <a class="header-anchor" href="#danh-cho-nguoi-khuyet-tat" aria-label="Permalink to “Dành cho người khuyết tật”">​</a></h1><p>Website thudung.net có hỗ trợ Trình đọc màn hình cho người khiếm thị, đáp ứng Thông tư số 28/2009/TT-BTTTT của Bộ Thông tin và Truyền thông: Quy định việc áp dụng tiêu chuẩn, công nghệ hỗ trợ người khuyết tật tiếp cận, sử dụng công nghệ thông tin và truyền thông. (<a href="https://mst.gov.vn/van-ban-phap-luat/9829.htm" target="_blank" rel="noreferrer">https://mst.gov.vn/van-ban-phap-luat/9829.htm</a>)</p><p>Có thể dùng trên Máy tính hay điện thoại di động để đọc nội dung webite cho người khiếm thị.</p><p>Chuẩn công nghiệp áp dụng là WAI-ARIA (<a href="https://www.w3.org/WAI/standards-guidelines/aria/" target="_blank" rel="noreferrer">https://www.w3.org/WAI/standards-guidelines/aria/</a> ) và áp dụng các phương pháp triển khai a11y (accessibility).</p><p>Để bật trình đọc màn hình trên máy tính, bạn có thể tham khảo các hướng dẫn sau:</p><h2 id="huong-dan-bat-trinh-đoc-man-hinh" tabindex="-1">Hướng dẫn bật trình đọc màn hình <a class="header-anchor" href="#huong-dan-bat-trinh-đoc-man-hinh" aria-label="Permalink to “Hướng dẫn bật trình đọc màn hình”">​</a></h2><h3 id="tren-may-tinh" tabindex="-1">Trên máy tính <a class="header-anchor" href="#tren-may-tinh" aria-label="Permalink to “Trên máy tính”">​</a></h3><ul><li><strong>Windows:</strong> Sử dụng Narrator (Windows Key + Ctrl + Enter) hoặc các phần mềm của bên thứ ba như NVDA (miễn phí) hoặc JAWS (có phí).</li><li><strong>macOS:</strong> Sử dụng VoiceOver (Command + F5).</li></ul><h3 id="tren-đien-thoai-di-đong" tabindex="-1">Trên điện thoại di động <a class="header-anchor" href="#tren-đien-thoai-di-đong" aria-label="Permalink to “Trên điện thoại di động”">​</a></h3><ul><li><strong>Android:</strong> Sử dụng TalkBack (Cài đặt &gt; Hỗ trợ tiếp cận &gt; TalkBack).</li><li><strong>iOS:</strong> Sử dụng VoiceOver (Cài đặt &gt; Trợ năng &gt; VoiceOver).</li></ul><h2 id="cac-trinh-duyet-web-ho-tro" tabindex="-1">Các trình duyệt web hỗ trợ <a class="header-anchor" href="#cac-trinh-duyet-web-ho-tro" aria-label="Permalink to “Các trình duyệt web hỗ trợ”">​</a></h2><p>Các trình duyệt web hiện đại như Google Chrome, Mozilla Firefox, Microsoft Edge và Safari đều có khả năng tương thích tốt với các trình đọc màn hình.</p><p>Để có trải nghiệm tốt nhất, hãy đảm bảo rằng trình duyệt của bạn luôn được cập nhật lên phiên bản mới nhất.</p><p>Nội dung được cập nhật lúc 14:56 Thứ Bảy, 21 tháng 3, 2026.</p>',14)])])}const p=t(i,[["render",e]]);export{u as __pageData,p as default};
